### Step 2: Add or update code snippets

Create the file `sdk/blueprint/Azure.ResourceManager.Blueprint/tests/Samples/Sample1_Blueprint.cs`:

```csharp
// Copyright (c) Microsoft Corporation. All rights reserved.
// Licensed under the MIT License.

using System;
using System.Threading.Tasks;
using Azure.Identity;
using Azure.ResourceManager;
using Azure.ResourceManager.Blueprint;
using Azure.ResourceManager.Blueprint.Models;
using NUnit.Framework;

namespace Azure.ResourceManager.Blueprint.Tests.Samples
{
    public class Sample1_Blueprint
    {
        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task AuthenticateClient()
        {
            #region Snippet:Blueprint_AuthenticateClient
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            #endregion
        }

        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateBlueprint()
        {
            #region Snippet:Blueprint_CreateBlueprint
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            string subscriptionId = "<subscription-id>";
            string blueprintName = "myBlueprint";

            // Blueprints can be scoped to a subscription or management group.
            // Here we use a subscription scope.
            var scope = $"/subscriptions/{subscriptionId}";
            var blueprintCollection = client.GetBlueprints(new ResourceIdentifier(scope));

            var blueprintData = new BlueprintData
            {
                Description = "My sample blueprint",
                TargetScope = BlueprintTargetScope.Subscription,
            };

            var operation = await blueprintCollection.CreateOrUpdateAsync(
                Azure.WaitUntil.Completed,
                blueprintName,
                blueprintData);

            BlueprintResource blueprint = operation.Value;
            Console.WriteLine($"Created blueprint: {blueprint.Data.Name}");
            #endregion
        }

        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task PublishBlueprint()
        {
            #region Snippet:Blueprint_PublishBlueprint
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            string subscriptionId = "<subscription-id>";
            string blueprintName = "myBlueprint";
            string version = "v1";

            var scope = $"/subscriptions/{subscriptionId}";
            var blueprintCollection = client.GetBlueprints(new ResourceIdentifier(scope));
            BlueprintResource blueprint = await blueprintCollection.GetAsync(blueprintName);

            var publishedCollection = blueprint.GetPublishedBlueprints();
            var publishedData = new PublishedBlueprintData();

            var operation = await publishedCollection.CreateOrUpdateAsync(
                Azure.WaitUntil.Completed,
                version,
                publishedData);

            PublishedBlueprintResource published = operation.Value;
            Console.WriteLine($"Published blueprint version: {published.Data.Name}");
            #endregion
        }

        [Test]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateAssignment()
        {
            #region Snippet:Blueprint_CreateAssignment
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            string subscriptionId = "<subscription-id>";
            string assignmentName = "myAssignment";
            string blueprintId =
                $"/subscriptions/{subscriptionId}/providers/Microsoft.Blueprint/blueprints/myBlueprint/versions/v1";

            var scope = $"/subscriptions/{subscriptionId}";
            var assignmentCollection = client.GetAssignments(new ResourceIdentifier(scope));

            var assignmentData = new AssignmentData(
                new AssignmentIdentity(AssignmentIdentityType.SystemAssigned),
                Azure.Core.AzureLocation.EastUS,
                blueprintId,
                new System.Collections.Generic.Dictionary<string, AssignmentParameterValue>(),
                new System.Collections.Generic.Dictionary<string, AssignmentResourceGroup>());

            var operation = await assignmentCollection.CreateOrUpdateAsync(
                Azure.WaitUntil.Completed,
                assignmentName,
                assignmentData);

            AssignmentResource assignment = operation.Value;
            Console.WriteLine($"Created assignment: {assignment.Data.Name}, Status: {assignment.Data.ProvisioningState}");
            #endregion
        }
    }
}
```

For each snippet:
- `Blueprint_AuthenticateClient` → README section "Authenticate the client"
- `Blueprint_CreateBlueprint` → README section "Examples > Create a blueprint"
- `Blueprint_PublishBlueprint` → README section "Examples > Publish a blueprint version"
- `Blueprint_CreateAssignment` → README section "Examples > Create a blueprint assignment"

